/* ------------------------------------------------------------------ */
/* Settings bridge (Python)                                            */
/* ------------------------------------------------------------------ */

interface Settings {
  installedOnly: boolean;
  playtimeBucket: "all" | "unplayed" | "under2h" | "under10h";
  deckCompat: "any" | "playable" | "verified";
  oneSitting: boolean;
  oneSittingHours: number;
  avoidRecent: boolean;
  weightNeglected: boolean;
  sound: boolean;
  haptics: boolean;
  recent: number[];
}

const DEFAULT_SETTINGS: Settings = {
  installedOnly: true,
  playtimeBucket: "all",
  deckCompat: "any",
  oneSitting: false,
  oneSittingHours: 3,
  avoidRecent: true,
  weightNeglected: true,
  sound: true,
  haptics: true,
  recent: [],
};

const getSettings = callable<[], Settings>("get_settings");
const setSettings = callable<[Settings], boolean>("set_settings");
const recordRoll = callable<[number], number[]>("record_roll");
const getHltb = callable<[string], number | null>("get_hltb");

/* ------------------------------------------------------------------ */
/* Steam library access                                                */
/*                                                                     */
/* Reaches into live Steam client stores. Field shapes are taken from  */
/* @decky/ui's SteamClient typings but every access is defensive: a    */
/* Valve rename degrades to "no games" rather than a crash.            */
/* ------------------------------------------------------------------ */

// ESteamDeckCompatibilityCategory: 0 Unknown, 1 Unsupported, 2 Playable, 3 Verified
const COMPAT_PLAYABLE = 2;
const COMPAT_VERIFIED = 3;
const APP_TYPE_GAME = 1; // EAppType.Game

interface Game {
  appid: number;
  name: string;
  minutes: number;
  installed: boolean;
  compat: number;
}

function overviewToGame(app: any): Game | null {
  if (!app) return null;
  const type = Number(app.app_type ?? 0);
  if (type !== 0 && (type & APP_TYPE_GAME) === 0) return null;
  const appid = Number(app.appid);
  if (!Number.isFinite(appid)) return null;
  return {
    appid,
    name: String(app.display_name ?? "Unknown"),
    minutes: Number(app.minutes_playtime_forever ?? 0) || 0,
    installed: Boolean(app.installed),
    compat: Number(app.steam_deck_compat_category ?? 0) || 0,
  };
}

function readLibrary(): Game[] {
  const store = (window as any).collectionStore;
  const raw: any[] = store?.allAppsCollection?.allApps ?? [];
  const games: Game[] = [];
  for (const app of raw) {
    const g = overviewToGame(app);
    if (g) games.push(g);
  }
  return games;
}

function lookupGame(appid: number, library: Game[]): Game | null {
  const hit = library.find((g) => g.appid === appid);
  if (hit) return hit;
  // Fall back to the app store for games not in the filtered library snapshot.
  const overview = (window as any).appStore?.GetAppOverviewByAppID?.(appid);
  return overviewToGame(overview);
}

function capsuleUrl(appid: number): string {
  return `https://steamloopback.host/assets/${appid}/library_600x900.jpg`;
}

function headerUrl(appid: number): string {
  return `https://steamloopback.host/assets/${appid}/header.jpg`;
}

function launchGame(appid: number): void {
  try {
    (window as any).SteamClient?.Apps?.RunGame(`${appid}`, "", -1, 100);
  } catch (err) {
    console.error("[GameRoulette] launch failed", err);
    toaster.toast({ title: "Game Roulette", body: "Couldn't launch that one." });
  }
}

function viewInLibrary(appid: number): void {
  try {
    Navigation.Navigate(`/library/app/${appid}`);
    Navigation.CloseSideMenus();
  } catch (err) {
    console.error("[GameRoulette] navigate failed", err);
    toaster.toast({ title: "Game Roulette", body: "Couldn't open that game's page." });
  }
}

const VERSION = "1.0.0";
const GITHUB_URL = "https://github.com/ayrshirepixels/game-roulette";

function openExternal(url: string): void {
  try {
    Navigation.NavigateToExternalWeb(url);
    Navigation.CloseSideMenus();
  } catch (err) {
    console.error("[GameRoulette] external nav failed", err);
    toaster.toast({ title: "Game Roulette", body: "Couldn't open the browser." });
  }
}

/* ------------------------------------------------------------------ */
/* Feedback: sound + haptics on land                                   */
/* ------------------------------------------------------------------ */

let audioCtx: AudioContext | null = null;

function playClunk(): void {
  try {
    const Ctx = (window as any).AudioContext || (window as any).webkitAudioContext;
    if (!Ctx) return;
    if (!audioCtx) audioCtx = new Ctx();
    const ctx = audioCtx!;
    if (ctx.state === "suspended") ctx.resume();
    const now = ctx.currentTime;

    // Low mechanical thump: a quick downward pitch drop with a fast decay.
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = "triangle";
    osc.frequency.setValueAtTime(150, now);
    osc.frequency.exponentialRampToValueAtTime(55, now + 0.09);
    gain.gain.setValueAtTime(0.0001, now);
    gain.gain.exponentialRampToValueAtTime(0.32, now + 0.005);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + 0.16);
    osc.connect(gain).connect(ctx.destination);
    osc.start(now);
    osc.stop(now + 0.18);

    // Short noise tick layered on top for the "clack".
    const buffer = ctx.createBuffer(1, ctx.sampleRate * 0.03, ctx.sampleRate);
    const ch = buffer.getChannelData(0);
    for (let i = 0; i < ch.length; i++) ch[i] = (Math.random() * 2 - 1) * (1 - i / ch.length);
    const noise = ctx.createBufferSource();
    const ngain = ctx.createGain();
    const lp = ctx.createBiquadFilter();
    lp.type = "lowpass";
    lp.frequency.value = 2200;
    ngain.gain.setValueAtTime(0.18, now);
    ngain.gain.exponentialRampToValueAtTime(0.0001, now + 0.05);
    noise.buffer = buffer;
    noise.connect(lp).connect(ngain).connect(ctx.destination);
    noise.start(now);
  } catch (err) {
    console.warn("[GameRoulette] sound failed", err);
  }
}

function pulseHaptic(): void {
  try {
    // TriggerHapticPulse(controllerIndex, eHapticType, param2); type 2 == Click.
    (window as any).SteamClient?.Input?.TriggerHapticPulse?.(0, 2, 0);
  } catch {
    /* haptics are best-effort */
  }
}

/* ------------------------------------------------------------------ */
/* Filtering + weighted pick                                           */
/* ------------------------------------------------------------------ */

function applyFilters(all: Game[], s: Settings): Game[] {
  let pool = all;
  if (s.installedOnly) pool = pool.filter((g) => g.installed);

  switch (s.playtimeBucket) {
    case "unplayed":
      pool = pool.filter((g) => g.minutes === 0);
      break;
    case "under2h":
      pool = pool.filter((g) => g.minutes < 120);
      break;
    case "under10h":
      pool = pool.filter((g) => g.minutes < 600);
      break;
  }

  if (s.deckCompat === "verified") pool = pool.filter((g) => g.compat === COMPAT_VERIFIED);
  else if (s.deckCompat === "playable") pool = pool.filter((g) => g.compat >= COMPAT_PLAYABLE);

  if (s.avoidRecent && s.recent.length) {
    const trimmed = pool.filter((g) => !s.recent.includes(g.appid));
    if (trimmed.length >= 5) pool = trimmed;
  }
  return pool;
}

function pickWinner(pool: Game[], weighted: boolean): Game {
  if (!weighted) return pool[Math.floor(Math.random() * pool.length)];
  const weights = pool.map((g) => 1 / (g.minutes + 30));
  const total = weights.reduce((a, b) => a + b, 0);
  let roll = Math.random() * total;
  for (let i = 0; i < pool.length; i++) {
    roll -= weights[i];
    if (roll <= 0) return pool[i];
  }
  return pool[pool.length - 1];
}

function sample<T>(arr: T[], n: number): T[] {
  const out: T[] = [];
  for (let i = 0; i < n; i++) out.push(arr[Math.floor(Math.random() * arr.length)]);
  return out;
}

function playtimeLabel(minutes: number): string {
  if (minutes <= 0) return "never played";
  if (minutes < 60) return `${minutes}m played`;
  return `${(minutes / 60).toFixed(minutes < 600 ? 1 : 0)}h played`;
}

/* ------------------------------------------------------------------ */
/* Reel visual constants                                               */
/* ------------------------------------------------------------------ */

const ITEM_W = 92;
const ITEM_H = 138;
const GAP = 8;
const VISIBLE = 3;
const STRIP_LEN = 30;
const WINNER_INDEX = STRIP_LEN - 3;
const SPIN_MS = 3200;

function Capsule({ game, highlight }: { game: Game; highlight: boolean }) {
  const [src, setSrc] = useState(capsuleUrl(game.appid));
  const [fellBack, setFellBack] = useState(false);
  return (
    <div
      style={{
        width: ITEM_W,
        height: ITEM_H,
        flex: "0 0 auto",
        borderRadius: 6,
        overflow: "hidden",
        position: "relative",
        background: "#1a1f2b",
        boxShadow: highlight
          ? "0 0 0 2px #ffd24a, 0 0 14px rgba(255, 210, 74, 0.55)"
          : "0 1px 3px rgba(0,0,0,0.5)",
        transition: "box-shadow 180ms ease",
      }}
    >
      <img
        src={src}
        alt={game.name}
        onError={() => {
          if (!fellBack) {
            setFellBack(true);
            setSrc(headerUrl(game.appid));
          }
        }}
        style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
      />
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* Recent rolls (collapsible)                                          */
/* ------------------------------------------------------------------ */

function RecentRolls({ recent, library }: { recent: number[]; library: Game[] }) {
  const [open, setOpen] = useState(false);
  if (!recent.length) return null;
  const games = recent
    .map((id) => lookupGame(id, library))
    .filter((g): g is Game => g !== null);

  return (
    <PanelSection title="Recent rolls">
      <PanelSectionRow>
        <ButtonItem layout="below" onClick={() => setOpen((v) => !v)}>
          {open ? "Hide" : "Show"} last {games.length}
        </ButtonItem>
      </PanelSectionRow>
      {open &&
        games.map((g) => (
          <PanelSectionRow key={g.appid}>
            <ButtonItem
              layout="below"
              onClick={() => launchGame(g.appid)}
              description={playtimeLabel(g.minutes)}
            >
              {g.name}
            </ButtonItem>
          </PanelSectionRow>
        ))}
    </PanelSection>
  );
}

/* ------------------------------------------------------------------ */
/* Main panel                                                          */
/* ------------------------------------------------------------------ */

type Phase = "idle" | "searching" | "spinning" | "done";

function Content() {
  const [settings, setSettingsState] = useState<Settings>(DEFAULT_SETTINGS);
  const [library, setLibrary] = useState<Game[]>([]);
  const [phase, setPhase] = useState<Phase>("idle");
  const [strip, setStrip] = useState<Game[]>([]);
  const [winner, setWinner] = useState<Game | null>(null);
  const [why, setWhy] = useState<string>("");

  const trackRef = useRef<HTMLDivElement | null>(null);
  const settledRef = useRef(false);
  const hltbCache = useRef<Map<string, number | null>>(new Map());
  const settingsRef = useRef<Settings>(settings);
  settingsRef.current = settings;

  useEffect(() => {
    let alive = true;
    (async () => {
      try {
        const s = await getSettings();
        if (alive) setSettingsState(s);
      } catch {
        /* defaults */
      }
      if (alive) setLibrary(readLibrary());
    })();
    return () => {
      alive = false;
    };
  }, []);

  const pool = useMemo(() => applyFilters(library, settings), [library, settings]);

  function persist(next: Settings) {
    setSettingsState(next);
    setSettings(next).catch(() => undefined);
  }
  function update<K extends keyof Settings>(key: K, value: Settings[K]) {
    persist({ ...settings, [key]: value });
  }

  async function hltbHours(name: string): Promise<number | null> {
    if (hltbCache.current.has(name)) return hltbCache.current.get(name)!;
    let h: number | null = null;
    try {
      h = await getHltb(name);
    } catch {
      h = null;
    }
    hltbCache.current.set(name, h);
    return h;
  }

  // Pick a game whose HLTB main story fits the "one sitting" threshold.
  async function pickShort(
    from: Game[],
  ): Promise<{ game: Game | null; note?: string }> {
    const s = settingsRef.current;
    const tried = new Set<number>();
    let anyResolved = false;
    let shortest: { g: Game; h: number } | null = null;
    const maxTries = Math.min(12, from.length);

    for (let i = 0; i < maxTries; i++) {
      let c = pickWinner(from, s.weightNeglected);
      let guard = 0;
      while (tried.has(c.appid) && guard++ < 20) c = pickWinner(from, s.weightNeglected);
      tried.add(c.appid);

      const h = await hltbHours(c.name);
      if (h != null) {
        anyResolved = true;
        if (h <= s.oneSittingHours) return { game: c };
        if (!shortest || h < shortest.h) shortest = { g: c, h };
      }
    }
    if (!anyResolved) return { game: null, note: "Couldn't reach HowLongToBeat — rolled without the length filter." };
    if (shortest) return { game: shortest.g, note: `Nothing under ${settingsRef.current.oneSittingHours}h — landed on the shortest found (~${shortest.h}h).` };
    return { game: null, note: "No length data — rolled without the length filter." };
  }

  function runReel(chosen: Game) {
    const filler = sample(pool.length > 1 ? pool : library, STRIP_LEN);
    filler[WINNER_INDEX] = chosen;
    settledRef.current = false;
    setWinner(null);
    setWhy("");
    setStrip(filler);
    setPhase("spinning");

    const reduce = !!window.matchMedia?.("(prefers-reduced-motion: reduce)").matches;
    const centreOffset = (WINNER_INDEX - Math.floor(VISIBLE / 2)) * (ITEM_W + GAP);

    // Safety net: guarantee a landing even if the CSS transition never fires
    // (settle is idempotent via settledRef, so whichever path wins is fine).
    window.setTimeout(() => settle(chosen), reduce ? 0 : SPIN_MS + 250);

    const track = trackRef.current;
    if (!track) return;

    if (reduce) {
      track.style.transition = "none";
      track.style.transform = `translateX(-${centreOffset}px)`;
      return; // landing handled by the timeout above
    }

    // Reset to the start with no transition. transform is a compositor
    // property, so offsetHeight alone won't commit it — reading a computed
    // style value forces the reset to actually take before we animate.
    track.style.transition = "none";
    track.style.transform = "translateX(0px)";
    window.getComputedStyle(track).transform; // force style flush

    // Kick the spin off on a later frame so the reset paints first; this is
    // what makes the transition fire on the *second* spin (0 -> -offset is a
    // real change) rather than getting coalesced away.
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        const t = trackRef.current;
        if (!t) return;
        t.style.transition = `transform ${SPIN_MS}ms cubic-bezier(0.12, 0.8, 0.16, 1)`;
        t.style.transform = `translateX(-${centreOffset}px)`;
      });
    });
  }

  async function spin() {
    if (phase === "spinning" || phase === "searching") return;
    if (pool.length === 0) {
      toaster.toast({ title: "Game Roulette", body: "No games match those filters." });
      return;
    }

    if (settings.oneSitting) {
      setPhase("searching");
      const { game, note } = await pickShort(pool);
      if (note) toaster.toast({ title: "Game Roulette", body: note });
      const chosen = game ?? pickWinner(pool, settings.weightNeglected);
      runReel(chosen);
      return;
    }

    runReel(pickWinner(pool, settings.weightNeglected));
  }

  function buildWhy(g: Game): string {
    const s = settingsRef.current;
    const parts: string[] = [`Picked from ${pool.length} game${pool.length === 1 ? "" : "s"}`];
    if (s.weightNeglected) parts.push("weighted to neglected");
    parts.push(playtimeLabel(g.minutes));
    const h = hltbCache.current.get(g.name);
    if (h != null) parts.push(`~${h}h to beat`);
    return parts.join(" · ");
  }

  function settle(chosen: Game) {
    if (settledRef.current) return;
    settledRef.current = true;
    setWinner(chosen);
    setWhy(buildWhy(chosen));
    setPhase("done");
    if (settingsRef.current.sound) playClunk();
    if (settingsRef.current.haptics) pulseHaptic();
    recordRoll(chosen.appid)
      .then((recent) => setSettingsState((prev) => ({ ...prev, recent })))
      .catch(() => undefined);
  }

  const viewportW = VISIBLE * ITEM_W + (VISIBLE - 1) * GAP;
  const spinLabel =
    phase === "spinning" ? "Spinning…" :
    phase === "searching" ? "Finding a short one…" :
    phase === "done" ? "Spin again" : "Spin";

  return (
    <>
      <PanelSection>
        <PanelSectionRow>
          <Focusable style={{ display: "flex", justifyContent: "center", padding: "4px 0 10px" }}>
            <div
              style={{
                width: viewportW,
                height: ITEM_H,
                overflow: "hidden",
                position: "relative",
                borderRadius: 8,
                background: "#0c0f16",
                border: "1px solid #2a3140",
              }}
            >
              <div
                style={{
                  position: "absolute",
                  top: 0,
                  bottom: 0,
                  left: ITEM_W + GAP - 1,
                  width: ITEM_W + 2,
                  borderLeft: "1px solid rgba(255,210,74,0.25)",
                  borderRight: "1px solid rgba(255,210,74,0.25)",
                  pointerEvents: "none",
                  zIndex: 2,
                }}
              />
              <div
                ref={trackRef}
                onTransitionEnd={(e) => {
                  // Ignore transitions bubbling up from child capsules (e.g. the
                  // highlight box-shadow) — only the reel's own transform counts.
                  if (e.target !== trackRef.current || e.propertyName !== "transform") return;
                  if (phase === "spinning" && strip[WINNER_INDEX]) settle(strip[WINNER_INDEX]);
                }}
                style={{ display: "flex", gap: GAP, height: "100%", alignItems: "center", willChange: "transform" }}
              >
                {strip.length === 0 ? (
                  <div style={{ width: viewportW, textAlign: "center", color: "#6b7688", fontSize: 13, alignSelf: "center" }}>
                    Press Spin
                  </div>
                ) : (
                  strip.map((g, i) => (
                    <Capsule key={`${g.appid}-${i}`} game={g} highlight={phase === "done" && i === WINNER_INDEX} />
                  ))
                )}
              </div>
            </div>
          </Focusable>
        </PanelSectionRow>

        {phase === "done" && winner && (
          <>
            <PanelSectionRow>
              <div style={{ textAlign: "center", fontWeight: 700, fontSize: 15, padding: "2px 4px 2px", color: "#ffd24a" }}>
                {winner.name}
              </div>
            </PanelSectionRow>
            {why && (
              <PanelSectionRow>
                <div style={{ textAlign: "center", fontSize: 11, color: "#8b95a7", padding: "0 4px 6px", width: "100%" }}>
                  {why}
                </div>
              </PanelSectionRow>
            )}
            <PanelSectionRow>
              <ButtonItem layout="below" onClick={() => launchGame(winner.appid)}>
                Launch now
              </ButtonItem>
            </PanelSectionRow>
            <PanelSectionRow>
              <ButtonItem layout="below" onClick={() => viewInLibrary(winner.appid)}>
                View in library
              </ButtonItem>
            </PanelSectionRow>
          </>
        )}

        <PanelSectionRow>
          <ButtonItem layout="below" onClick={spin} disabled={phase === "spinning" || phase === "searching"}>
            {spinLabel}
          </ButtonItem>
        </PanelSectionRow>

        <PanelSectionRow>
          <div style={{ fontSize: 12, color: "#6b7688", textAlign: "center", width: "100%" }}>
            {pool.length} game{pool.length === 1 ? "" : "s"} in the pool
          </div>
        </PanelSectionRow>
        <PanelSectionRow>
          <div style={{ fontSize: 10, color: "#5a6473", textAlign: "center", width: "100%", letterSpacing: "0.3px" }}>
            Ayrshire Pixels
          </div>
        </PanelSectionRow>
      </PanelSection>

      <RecentRolls recent={settings.recent} library={library} />

      <PanelSection title="Filters">
        <PanelSectionRow>
          <ToggleField label="Installed only" checked={settings.installedOnly} onChange={(v) => update("installedOnly", v)} />
        </PanelSectionRow>
        <PanelSectionRow>
          <DropdownItem
            label="Playtime"
            rgOptions={[
              { data: "all", label: "Anything" },
              { data: "unplayed", label: "Never played" },
              { data: "under2h", label: "Under 2 hours" },
              { data: "under10h", label: "Under 10 hours" },
            ]}
            selectedOption={settings.playtimeBucket}
            onChange={(o) => update("playtimeBucket", o.data as Settings["playtimeBucket"])}
          />
        </PanelSectionRow>
        <PanelSectionRow>
          <DropdownItem
            label="Deck compatibility"
            rgOptions={[
              { data: "any", label: "Any" },
              { data: "playable", label: "Playable or better" },
              { data: "verified", label: "Verified only" },
            ]}
            selectedOption={settings.deckCompat}
            onChange={(o) => update("deckCompat", o.data as Settings["deckCompat"])}
          />
        </PanelSectionRow>
        <PanelSectionRow>
          <ToggleField
            label="One-sitting only"
            description={`Only games with a HowLongToBeat main story under ${settings.oneSittingHours} hours.`}
            checked={settings.oneSitting}
            onChange={(v) => update("oneSitting", v)}
          />
        </PanelSectionRow>
        <PanelSectionRow>
          <ToggleField
            label="Weight toward neglected"
            description="Rarely-played games land more often."
            checked={settings.weightNeglected}
            onChange={(v) => update("weightNeglected", v)}
          />
        </PanelSectionRow>
        <PanelSectionRow>
          <ToggleField
            label="Avoid recent rolls"
            description="Skip the last few games it landed on."
            checked={settings.avoidRecent}
            onChange={(v) => update("avoidRecent", v)}
          />
        </PanelSectionRow>
      </PanelSection>

      <PanelSection title="Feel">
        <PanelSectionRow>
          <ToggleField label="Sound on land" checked={settings.sound} onChange={(v) => update("sound", v)} />
        </PanelSectionRow>
        <PanelSectionRow>
          <ToggleField label="Haptics on land" checked={settings.haptics} onChange={(v) => update("haptics", v)} />
        </PanelSectionRow>
      </PanelSection>

      <PanelSection title="About">
        <PanelSectionRow>
          <Focusable style={{ display: "flex", alignItems: "center", gap: 10, padding: "2px 2px 8px" }}>
            <WheelIcon style={{ fontSize: 30, flex: "0 0 auto", color: "#e6ebf2" }} />
            <div style={{ display: "flex", flexDirection: "column", lineHeight: 1.25 }}>
              <span style={{ fontWeight: 700, fontSize: 14, color: "#e6ebf2" }}>Ayrshire Pixels</span>
              <span style={{ fontSize: 11, color: "#8b95a7" }}>Game Roulette v{VERSION}</span>
            </div>
          </Focusable>
        </PanelSectionRow>
        <PanelSectionRow>
          <ButtonItem layout="below" onClick={() => openExternal(GITHUB_URL)}>
            View on GitHub
          </ButtonItem>
        </PanelSectionRow>
        <PanelSectionRow>
          <div style={{ fontSize: 10, color: "#5a6473", textAlign: "center", width: "100%", padding: "2px 0 4px" }}>
            Made in Irvine, Ayrshire 🏴󠁧󠁢󠁳󠁣󠁴󠁿
          </div>
        </PanelSectionRow>
      </PanelSection>
    </>
  );
}

class Boundary extends Component<{ children: any }, { err: unknown }> {
  state = { err: null as unknown };
  static getDerivedStateFromError(err: unknown) {
    return { err };
  }
  componentDidCatch(err: unknown) {
    console.error("[GameRoulette] render error", err);
  }
  render() {
    if (this.state.err) {
      return (
        <PanelSection>
          <PanelSectionRow>
            <div style={{ padding: 8, color: "#ff8a8a", fontSize: 13, textAlign: "center" }}>
              Game Roulette hit an error. Close and reopen this menu to reset.
            </div>
          </PanelSectionRow>
        </PanelSection>
      );
    }
    return this.props.children;
  }
}

